node -e "
const fs = require('fs');
const { spawnSync } = require('child_process');
const assert = require('assert');
const rules = JSON.parse(fs.readFileSync('data/payout-rules.json', 'utf8'));
const events = [
  { id: 'c1', merchant_id: 'm1', type: 'charge', amount_cents: 100000 },
  { id: 'c1', merchant_id: 'm1', type: 'charge', amount_cents: 100000 },
  { id: 'r1', merchant_id: 'm1', type: 'refund', amount_cents: 5000 },
  { id: 'd1', merchant_id: 'm1', type: 'dispute', amount_cents: 20000 },
  { id: 'c2', merchant_id: 'm2', type: 'charge', amount_cents: 1000 },
];
fs.writeFileSync('/tmp/devlyn-payout-success.json', JSON.stringify({ events }));
const seen = new Map();
const order = [];
const rows = new Map();
for (const ev of events) {
  const content = JSON.stringify(ev);
  if (seen.has(ev.id)) {
    if (seen.get(ev.id) !== content) throw new Error('fixture has an unintended conflicting duplicate');
    continue;
  }
  seen.set(ev.id, content);
  if (!rows.has(ev.merchant_id)) {
    rows.set(ev.merchant_id, { merchant_id: ev.merchant_id, gross_charge_cents: 0, refund_cents: 0, dispute_cents: 0, processing_fee_cents: 0, dispute_fee_cents: 0 });
    order.push(ev.merchant_id);
  }
  const row = rows.get(ev.merchant_id);
  if (ev.type === 'charge') {
    row.gross_charge_cents += ev.amount_cents;
    row.processing_fee_cents += Math.round(ev.amount_cents * rules.processing_fee_percent / 100) + rules.fixed_fee_cents;
  } else if (ev.type === 'refund') {
    row.refund_cents += ev.amount_cents;
  } else if (ev.type === 'dispute') {
    row.dispute_cents += ev.amount_cents;
    row.dispute_fee_cents += rules.dispute_fee_cents;
  }
}
const merchants = order.map((mid) => {
  const row = rows.get(mid);
  const netBeforeReserve = row.gross_charge_cents - row.refund_cents - row.dispute_cents - row.processing_fee_cents - row.dispute_fee_cents;
  let reserve = netBeforeReserve > 0 ? Math.round(netBeforeReserve * rules.reserve_percent / 100) : 0;
  let payout = netBeforeReserve - reserve;
  if (payout > 0 && payout < rules.minimum_payout_cents) {
    reserve += payout;
    payout = 0;
  }
  return { merchant_id: row.merchant_id, gross_charge_cents: row.gross_charge_cents, refund_cents: row.refund_cents, dispute_cents: row.dispute_cents, processing_fee_cents: row.processing_fee_cents, dispute_fee_cents: row.dispute_fee_cents, reserve_cents: reserve, payout_cents: payout };
});
const expected = {
  total_payout_cents: merchants.reduce((s, m) => s + m.payout_cents, 0),
  total_processing_fee_cents: merchants.reduce((s, m) => s + m.processing_fee_cents, 0),
  total_dispute_fee_cents: merchants.reduce((s, m) => s + m.dispute_fee_cents, 0),
  total_reserve_cents: merchants.reduce((s, m) => s + m.reserve_cents, 0),
  merchants,
};
const res = spawnSync('node', ['bin/cli.js', 'payout', '--input', '/tmp/devlyn-payout-success.json'], { encoding: 'utf8' });
assert.strictEqual(res.status, 0, 'expected exit 0, got ' + res.status + ' stderr=' + res.stderr);
assert.strictEqual(res.stderr, '', 'expected no stderr, got ' + JSON.stringify(res.stderr));
const parsed = JSON.parse(res.stdout);
assert.deepStrictEqual(parsed, expected);
console.log('SUCCESS_CHECK_OK');
"

node -e "
const fs = require('fs');
const { spawnSync } = require('child_process');
const assert = require('assert');
const events = [
  { id: 'c1', merchant_id: 'm1', type: 'charge', amount_cents: 100000 },
  { id: 'c1', merchant_id: 'm1', type: 'charge', amount_cents: 200000 },
];
fs.writeFileSync('/tmp/devlyn-payout-conflict.json', JSON.stringify({ events }));
const res = spawnSync('node', ['bin/cli.js', 'payout', '--input', '/tmp/devlyn-payout-conflict.json'], { encoding: 'utf8' });
assert.strictEqual(res.status, 2, 'expected exit 2, got ' + res.status);
assert.strictEqual(res.stdout, '', 'expected empty stdout, got ' + JSON.stringify(res.stdout));
const errObj = JSON.parse(res.stderr.trim());
assert.deepStrictEqual(errObj, { error: 'conflicting_duplicate', id: 'c1' });
console.log('CONFLICT_CHECK_OK');
"

